/* ===== 刷新UI ===== */
static void update_ui(void)
{
    char buf[32];
    sprintf(buf, "Score: %d", score);
    lv_label_set_text(label_score, buf);

    for(int i = 0; i < 4; i++) {
        for(int j = 0; j < 4; j++) {
            char num[8];
            if(board[i][j] == 0)
                num[0] = '\0';
            else
                sprintf(num, "%d", board[i][j]);

            lv_obj_t * label = lv_obj_get_child(cells[i][j], 0);

            lv_label_set_text(label, num);

            lv_obj_set_style_bg_opa(cells[i][j], LV_OPA_COVER, 0);
            lv_color_t bg = get_color(board[i][j]);
            lv_obj_set_style_bg_color(cells[i][j], bg, 0);

            if(board[i][j] <= 4) {
                lv_obj_set_style_text_color(label, lv_color_hex(0x776E65), 0);
            } else {
                lv_obj_set_style_text_color(label, lv_color_hex(0xFFFFFF), 0);
            }
        }
    }
}

static lv_color_t get_color(int v)
{
    switch(v) {
        case 2: return lv_color_hex(0xEEE4DA);
        case 4: return lv_color_hex(0xEDE0C8);
        case 8: return lv_color_hex(0xF2B179);
        case 16: return lv_color_hex(0xF59563);
        case 32: return lv_color_hex(0xF67C5F);
        case 64: return lv_color_hex(0xF65E3B);
        case 128: return lv_color_hex(0xEDCF72);
        case 256: return lv_color_hex(0xEDCC61);
        case 512: return lv_color_hex(0xEDC850);
        case 1024: return lv_color_hex(0xEDC53F);
        case 2048: return lv_color_hex(0xEDC22E);
        default: return lv_color_hex(0xCDC1B4);
    }
}

/* ===== 随机生成 ===== */
static void spawn(void)
{
    int empty[16][2];
    int cnt = 0;

    for(int i = 0; i < 4; i++)
        for(int j = 0; j < 4; j++)
            if(board[i][j] == 0) {
                empty[cnt][0] = i;
                empty[cnt][1] = j;
                cnt++;
            }

    if(cnt == 0) return;

    int r = rand() % cnt;
    int x = empty[r][0];
    int y = empty[r][1];

    board[x][y] = (rand() % 2) ? 2 : 4;
}

/* ===== 左移 ===== */
static void move_left(void)
{
    for(int i = 0; i < 4; i++) {
        for(int j = 1; j < 4; j++) {
            if(board[i][j] == 0) continue;

            int k = j;
            while(k > 0 && board[i][k - 1] == 0) {
                board[i][k - 1] = board[i][k];
                board[i][k]     = 0;
                k--;
            }

            if(k > 0 && board[i][k - 1] == board[i][k]) {
                board[i][k - 1] *= 2;
                score += board[i][k - 1];
                board[i][k] = 0;
            }
        }
    }
}

/* ===== 右移 ===== */
static void move_right(void)
{
    for(int i = 0; i < 4; i++) {
        for(int j = 2; j >= 0; j--) {
            if(board[i][j] == 0) continue;

            int k = j;
            while(k < 3 && board[i][k + 1] == 0) {
                board[i][k + 1] = board[i][k];
                board[i][k]     = 0;
                k++;
            }

            if(k < 3 && board[i][k + 1] == board[i][k]) {
                board[i][k + 1] *= 2;
                score += board[i][k + 1];
                board[i][k] = 0;
            }
        }
    }
}

/* ===== 上移 ===== */
static void move_up(void)
{
    for(int j = 0; j < 4; j++) {
        for(int i = 1; i < 4; i++) {
            if(board[i][j] == 0) continue;

            int k = i;
            while(k > 0 && board[k - 1][j] == 0) {
                board[k - 1][j] = board[k][j];
                board[k][j]     = 0;
                k--;
            }

            if(k > 0 && board[k - 1][j] == board[k][j]) {
                board[k - 1][j] *= 2;
                score += board[k - 1][j];
                board[k][j] = 0;
            }
        }
    }
}

/* ===== 下移 ===== */
static void move_down(void)
{
    for(int j = 0; j < 4; j++) {
        for(int i = 2; i >= 0; i--) {
            if(board[i][j] == 0) continue;

            int k = i;
            while(k < 3 && board[k + 1][j] == 0) {
                board[k + 1][j] = board[k][j];
                board[k][j]     = 0;
                k++;
            }

            if(k < 3 && board[k + 1][j] == board[k][j]) {
                board[k + 1][j] *= 2;
                score += board[k + 1][j];
                board[k][j] = 0;
            }
        }
    }
}

