/* ===== 滑动逻辑 ===== */
static void gesture_event(lv_event_t * e)
{
    // 如果游戏已结束，不响应滑动
    if(game_over_flag) return;
    
    lv_dir_t dir = lv_indev_get_gesture_dir(lv_indev_get_act());
    int moved = 0;
    int old_board[4][4];
    
    // 保存移动前的棋盘状态
    memcpy(old_board, board, sizeof(board));
    int old_score = score;

    if(dir == LV_DIR_LEFT) move_left();
    else if(dir == LV_DIR_RIGHT) move_right();
    else if(dir == LV_DIR_TOP) move_up();
    else if(dir == LV_DIR_BOTTOM) move_down();
    else return;  // 不是有效的滑动方向
    
    // 检查棋盘是否有变化
    if(memcmp(old_board, board, sizeof(board)) != 0) {
        spawn();
        update_ui();
        
        if(is_game_over()) {
            game_over_flag = 1;
            show_game_over();
        }
    }
}

/* ===== 游戏结束判断 ===== */
static int is_game_over(void)
{
    for(int i = 0; i < 4; i++)
        for(int j = 0; j < 4; j++)
            if(board[i][j] == 0) return 0;

    for(int i = 0; i < 4; i++) {
        for(int j = 0; j < 4; j++) {
            if(i < 3 && board[i][j] == board[i + 1][j]) return 0;
            if(j < 3 && board[i][j] == board[i][j + 1]) return 0;
        }
    }
    return 1;
}

